USE master;
GO
IF EXISTS (
		SELECT		*
			FROM	sys.databases
			WHERE	name = 'OLAPExercise'
		)
BEGIN
	DROP DATABASE OLAPExercise;
END;
GO
CREATE DATABASE OLAPExercise;
ALTER DATABASE OLAPExercise
	SET RECOVERY SIMPLE
	WITH NO_WAIT;
GO
USE OLAPExercise;
GO


CREATE TABLE OP_VERKAUF
(
	FILIALNR		INT,
	FILIALE			VARCHAR(40),
	PLZ				CHAR(4),
	ORT				VARCHAR(30),
	ARTNR			VARCHAR(12),
	BEZEICHNUNG		VARCHAR(40),
	ARTIKELGRUPPE	VARCHAR(40),
	WARENKATEGORIE	VARCHAR(40),
	PREIS			DECIMAL(16, 2),
	MWST_SATZ		DECIMAL(16, 2),
	DATUM			DATETIME,
	MONAT			CHAR(2),
	JAHR			INT,
	KALENDERWOCHE	CHAR(2),
	WOCHENTAG		VARCHAR(10),
	ANZAHL			INT
);
 



